findings.suggestion:
提取为公共函数：
```js
function atomicWrite(filePath, data, options) {
  var tmp = filePath + ".tmp." + process.pid;
  fs.writeFileSync(tmp, typeof data === 'string' ? data : JSON.stringify(data, null, 2), options);
  fs.renameSync(tmp, filePath);
}

function atomicRead(filePath) {
  try {
    return JSON.parse(fs.readFileSync(filePath, "utf-8"));
  } catch {
    return null;
  }
}
```
之后所有 8+ 处写入统一使用 `atomicWrite()`。

